{% block content %}
<div class="container">
    <h2>Catálogo de Barcos</h2>

    <div class="filters">
        <form method="get" action="{% url 'catalog:barco_list' %}">
            <div style="display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 15px;">
                <div class="filter-group">
                    <label for="search">Buscar por nombre:</label>
                    <input type="text" id="search" name="search" value="{{ search_query }}" placeholder="Nombre del barco">
                </div>

                <div class="filter-group">
                    <label for="categoria">Categoría:</label>
                    <select id="categoria" name="categoria">
                        <option value="">Todas las categorías</option>
                        {% for cat in categorias %}
                            <option value="{{ cat.id }}">{{ cat.nombre }}</option>
                        {% endfor %}
                    </select>
                </div>

                <div class="filter-group">
                    <label for="puerto">Puerto:</label>
                    <select id="puerto" name="puerto">
                        <option value="">Todos los puertos</option>
                        {% for puerto in puertos %}
                            <option value="{{ puerto.id }}">{{ puerto.nombre }}</option>
                        {% endfor %}
                    </select>
                </div>

                <div class="filter-group">
                    <label for="fabricante">Fabricante:</label>
                    <select id="fabricante" name="fabricante">
                        <option value="">Todos los fabricantes</option>
                        {% for fab in fabricantes %}
                            <option value="{{ fab.id }}">{{ fab.nombre }}</option>
                        {% endfor %}
                    </select>
                </div>

                <div class="filter-group">
                    <label for="precio_min">Precio mínimo (€):</label>
                    <input type="number" id="precio_min" name="precio_min" step="0.01" placeholder="0.00">
                </div>

                <div class="filter-group">
                    <label for="precio_max">Precio máximo (€):</label>
                    <input type="number" id="precio_max" name="precio_max" step="0.01" placeholder="9999.99">
                </div>

                <div class="filter-group">
                    <label for="capacidad_min">Capacidad mínima:</label>
                    <input type="number" id="capacidad_min" name="capacidad_min" placeholder="1">
                </div>
            </div>
            <button type="submit" class="filter-button">Aplicar Filtros</button>
        </form>
    </div>

    {% if barcos %}
        <div class="barcos-grid">
            {% for barco in barcos %}
                <div class="barco-card">
                    <div class="barco-image">
                        {% if barco.imagen %}
                            <img src="{{ barco.imagen.url }}" alt="{{ barco.nombre }}" style="width: 100%; height: 100%; object-fit: cover;">
                        {% else %}
                            Sin imagen
                        {% endif %}
                    </div>
                    <div class="barco-info">
                        <h3>{{ barco.nombre }}</h3>
                        <p><strong>Categoría:</strong> {{ barco.categoria.nombre }}</p>
                        <p><strong>Fabricante:</strong> {{ barco.fabricante.nombre }}</p>
                        <p><strong>Puerto:</strong> {{ barco.puerto.nombre }}</p>
                        <p><strong>Capacidad:</strong> {{ barco.capacidad }} personas</p>
                        <div class="barco-precio">{{ barco.precio_dia }}€ / día</div>
                        {% if barco.disponible %}
                            <p class="barco-disponible">✓ Disponible</p>
                        {% else %}
