{% block content %}
<div class="container">
    <h2>Mi Cesta</h2>

    {% if barcos_en_cesta %}
        <div class="cesta-container">
            <div class="cesta-items">
                {% for item in barcos_en_cesta %}
                    <div class="item-cesta">
                        <div class="item-imagen">
                            {% if item.barco.imagen %}
                                <img src="{{ item.barco.imagen.url }}" alt="{{ item.barco.nombre }}" style="width: 100%; height: 100%; object-fit: cover; border-radius: 4px;">
                            {% else %}
                                Sin imagen
                            {% endif %}
                        </div>
                        <div class="item-info">
                            <h4>{{ item.barco.nombre }}</h4>
                            <p>{{ item.barco.precio_dia }}€ / día</p>
                            <p>{{ item.barco.categoria.nombre }}</p>
                        </div>
                        <div class="item-cantidad">
                            <form method="post" action="{% url 'cart:update' %}" style="display: flex; gap: 5px;">
                                {% csrf_token %}
                                <input type="hidden" name="barco_id" value="{{ item.barco.id }}">
                                <input type="number" name="cantidad" value="{{ item.cantidad }}" min="1" max="10">
                                <button type="submit" style="padding: 5px 10px; background-color: #003d82; color: white; border: none; border-radius: 4px; cursor: pointer;">✓</button>
                            </form>
                        </div>
                        <div class="item-subtotal">{{ item.subtotal }}€</div>
                        <form method="post" action="{% url 'cart:remove' %}" style="display: inline;">
                            {% csrf_token %}
                            <input type="hidden" name="barco_id" value="{{ item.barco.id }}">
                            <button type="submit" class="item-eliminar">✕</button>
                        </form>
                    </div>
                {% endfor %}
            </div>

            <div class="cesta-resumen">
                <h3>Resumen</h3>
                <div class="resumen-item">
                    <span>Artículos:</span>
                    <span>{{ cart_count }}</span>
                </div>
                <div class="resumen-total">
                    <span>Total:</span>
                    <span>{{ total }}€</span>
                </div>

                <form method="post" action="{% url 'cart:clear' %}">
                    {% csrf_token %}
                    <button type="submit" class="btn-vaciar">Vaciar cesta</button>
                </form>

                <a href="{% url 'catalog:barco_list' %}" style="display: block; text-align: center; padding: 12px; background-color: #6c757d; color: white; text-decoration: none; border-radius: 4px; margin-top: 10px;">Continuar comprando</a>

                <button class="btn-continuar" onclick="alert('Funcionalidad de reserva próximamente'); return false;">Proceder a reservar</button>
            </div>
        </div>
    {% else %}
        <div class="cesta-vacia">
            <p>Tu cesta está vacía.</p>
            <p><a href="{% url 'catalog:barco_list' %}">Ir al catálogo</a></p>
        </div>
    {% endif %}
</div>
{% endblock %}

